const response = $input.first().json;


// ----------------------------------------
// 1. READ GEMINI RESPONSE SAFELY
// ----------------------------------------

const raw =
  response?.candidates?.[0]?.content?.parts?.[0]?.text;

if (!raw || typeof raw !== 'string') {
  return [{
    json: {
      status: 'invalid',
      reason: 'Missing or empty Gemini response'
    }
  }];
}


// ----------------------------------------
// 2. CLEAN POSSIBLE MARKDOWN FENCES
// ----------------------------------------

const cleaned = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();


// ----------------------------------------
// 3. PARSE JSON
// ----------------------------------------

let data;

try {
  data = JSON.parse(cleaned);
} catch (error) {
  return [{
    json: {
      status: 'invalid',
      reason: 'JSON parse failed',
      raw
    }
  }];
}


// ----------------------------------------
// 4. REQUIRED FIELD VALIDATION
// ----------------------------------------

const requiredFields = [
  'vendor_name',
  'invoice_number',
  'invoice_date',
  'total_amount',
  'currency'
];

const missingFields = requiredFields.filter(field =>
  data[field] === null ||
  data[field] === undefined ||
  data[field] === ''
);

if (missingFields.length > 0) {
  return [{
    json: {
      status: 'invalid',
      reason:
        `Missing required fields: ${missingFields.join(', ')}`,
      data
    }
  }];
}


// ----------------------------------------
// 5. TOTAL AMOUNT VALIDATION
// ----------------------------------------

const invoiceTotal = Number(data.total_amount);

if (
  !Number.isFinite(invoiceTotal) ||
  invoiceTotal <= 0
) {
  return [{
    json: {
      status: 'invalid',
      reason:
        `Invalid total amount: ${data.total_amount}`,
      data
    }
  }];
}


// ----------------------------------------
// 6. LINE ITEMS MUST EXIST
// ----------------------------------------

if (
  !Array.isArray(data.line_items) ||
  data.line_items.length === 0
) {
  return [{
    json: {
      status: 'invalid',
      reason: 'No line items found',
      data
    }
  }];
}


// ----------------------------------------
// 7. VALIDATE EACH LINE ITEM
// ----------------------------------------

for (
  let i = 0;
  i < data.line_items.length;
  i++
) {

  const item = data.line_items[i];

  if (
    !item.description ||
    typeof item.description !== 'string'
  ) {
    return [{
      json: {
        status: 'invalid',
        reason:
          `Line item ${i + 1}: missing description`,
        data
      }
    }];
  }

  const lineTotal = Number(
    item.line_total ?? item.amount
  );

  if (
    !Number.isFinite(lineTotal) ||
    lineTotal < 0
  ) {
    return [{
      json: {
        status: 'invalid',
        reason:
          `Line item ${i + 1}: invalid line_total`,
        data
      }
    }];
  }
}


// ----------------------------------------
// 8. CALCULATE LINE ITEMS TOTAL
// ----------------------------------------

const lineItemsTotal =
  data.line_items.reduce(
    (sum, item) =>
      sum +
      Number(
        item.line_total ??
        item.amount
      ),
    0
  );


// ----------------------------------------
// 9. READ FINANCIAL FIELDS SAFELY
// ----------------------------------------

const subtotal = Number(
  data.subtotal ?? lineItemsTotal
);

const possibleTaxValues = [
  data.tax,
  data.tax_amount,
  data.total_tax,
  data.vat,
  data.vat_amount
];

let taxAmount = 0;

for (const value of possibleTaxValues) {

  const numericValue = Number(value);

  if (
    value !== null &&
    value !== undefined &&
    value !== '' &&
    Number.isFinite(numericValue)
  ) {
    taxAmount = numericValue;
    break;
  }
}

const shipping = Number(
  data.shipping ??
  data.shipping_amount ??
  0
);

const discount = Number(
  data.discount ??
  data.discount_amount ??
  0
);


// ----------------------------------------
// 10. FINANCIAL RECONCILIATION
// ----------------------------------------

const subtotalDifference = Math.abs(
  lineItemsTotal - subtotal
);

const expectedTotal =
  subtotal +
  taxAmount +
  shipping -
  discount;

const expectedDifference = Math.abs(
  expectedTotal - invoiceTotal);

const directDifference = Math.abs(
  lineItemsTotal - invoiceTotal
);

const TOLERANCE = 1;

let reconciliationMethod = null;
let finalDifference = null;


// CASE 1
// Line items == Invoice total

if (directDifference <= TOLERANCE) {

  reconciliationMethod =
    "LINE_ITEMS_EQUAL_TOTAL";

  finalDifference =
    directDifference;
}


// CASE 2
// Subtotal + Tax + Shipping - Discount == Invoice Total

else if (expectedDifference <= TOLERANCE) {

  reconciliationMethod =
    "FULL_FINANCIAL_RECONCILIATION";

  finalDifference =
    expectedDifference;
}


// CASE 3
// Invalid financial data

else {

  return [{
    json: {

      status: "invalid",

      reason:
        `Financial reconciliation failed. ` +
        `Expected ${expectedTotal.toFixed(2)} ` +
        `vs Invoice ${invoiceTotal.toFixed(2)}`,

      reconciliation: {

        line_items_total:
          Number(lineItemsTotal.toFixed(2)),

        subtotal:
          Number(subtotal.toFixed(2)),

        subtotal_difference:
          Number(subtotalDifference.toFixed(2)),

        tax:
          Number(taxAmount.toFixed(2)),

        shipping:
          Number(shipping.toFixed(2)),

        discount:
          Number(discount.toFixed(2)),

        expected_total:
          Number(expectedTotal.toFixed(2)),

        invoice_total:
          Number(invoiceTotal.toFixed(2)),

        difference:
          Number(expectedDifference.toFixed(2))
      },

      data
    }
  }];
}


// ----------------------------------------
// 11. VALID RESULT
// ----------------------------------------

return [{
  json: {

    status: "valid",

    reconciliation: {

      method:
        reconciliationMethod,

      line_items_total:
        Number(lineItemsTotal.toFixed(2)),

      subtotal:
        Number(subtotal.toFixed(2)),

      subtotal_difference:
        Number(subtotalDifference.toFixed(2)),

      tax:
        Number(taxAmount.toFixed(2)),

      shipping:
        Number(shipping.toFixed(2)),

      discount:
        Number(discount.toFixed(2)),

      expected_total:
        Number(expectedTotal.toFixed(2)),

      invoice_total:
        Number(invoiceTotal.toFixed(2)),

      difference:
        Number(finalDifference.toFixed(2))
    },

    data
  }
}];

// --------------------------------------------------
// 1. GET VALIDATED INVOICE DATA
// --------------------------------------------------

const validation =
  $('Validation Invoice Data').first().json;

const data = validation.data;

if (!data) {
  return [{
    json: {
      status: 'invalid',
      reason: 'Validated invoice data not found'
    }
  }];
}


// --------------------------------------------------
// 2. RESOLVE VENDOR ID
// Supports both:
// - existing vendor
// - newly created vendor
// --------------------------------------------------

const current = $input.first().json;

const vendorId =
  current.contact_id ||
  current.contact?.contact_id;

if (!vendorId) {
  return [{
    json: {
      status: 'invalid',
      reason: 'Zoho vendor ID not found'
    }
  }];
}


// --------------------------------------------------
// 3. BUILD ZOHO LINE ITEMS
// --------------------------------------------------

const zohoLineItems = data.line_items.map((item, index) => {

  const finalLineTotal = Number(
    item.line_total ?? item.amount
  );

  return {
    name: (
      item.description ||
      `Invoice Item ${index + 1}`
    ).slice(0, 190),

    rate: Number(finalLineTotal.toFixed(2)),

    quantity: 1,

    account_id: '3969563000000000549'
  };
});


// --------------------------------------------------
// 4. BUILD THE EXACT ZOHO PAYLOAD
// --------------------------------------------------

const payload = {
  vendor_id: String(vendorId),

  bill_number: String(data.invoice_number),

  date: String(data.invoice_date),

  line_items: zohoLineItems
};


// --------------------------------------------------
// 5. CALCULATE EXACT AMOUNT ZOHO WILL CREATE
// --------------------------------------------------

const zohoPayloadTotal = payload.line_items.reduce(
  (sum, item) =>
    sum + (Number(item.rate) * Number(item.quantity)),
  0
);

const invoiceTotal = Number(data.total_amount);

const difference = Math.abs(
  zohoPayloadTotal - invoiceTotal
);

const TOLERANCE = 1;


// --------------------------------------------------
// 6. BLOCK UNSAFE PAYLOAD
// --------------------------------------------------

if (difference > TOLERANCE) {
  return [{
    json: {
      status: 'invalid',

      reason:
        `Zoho payload reconciliation failed: ` +
        `payload total ${zohoPayloadTotal.toFixed(2)} ` +
        `vs invoice total ${invoiceTotal.toFixed(2)}`,

      reconciliation: {
        zoho_payload_total:
          Number(zohoPayloadTotal.toFixed(2)),

        invoice_total:
          Number(invoiceTotal.toFixed(2)),

        difference:
          Number(difference.toFixed(2))
      },

      payload
    }
  }];
}


// --------------------------------------------------
// 7. SAFE PAYLOAD
// --------------------------------------------------

return [{
  json: {
    status: 'valid',

    reconciliation: {
      zoho_payload_total:
        Number(zohoPayloadTotal.toFixed(2)),

      invoice_total:
        Number(invoiceTotal.toFixed(2)),

      difference:
        Number(difference.toFixed(2))
    },

    payload
  }
}];

const data = $('Validation Invoice Data').first().json.data;

return [{
  json: {
    contact_name: data.vendor_name,
    company_name: data.vendor_name,
    contact_type: 'vendor'
  }
}];
